import { invokeFunction, isArray } from '../../utils/zcutils';
import { isFunction } from '../../utils/function-utils';
import { ALLOWED_DOMAIN_OPERATORS } from '../operators/allowed-operators';

export function parseDomain() {
    let _scale = this,
        _config = _scale.config,
        _field = _config.field,
        _domainConfig = _config.domain,
        _datatype = '';

    if (isArray(_domainConfig)) {
        return _domainConfig;
    }

    if (isFunction(_domainConfig)) {
        invokeFunction(_domainConfig, this);
        return;
    }

    let appliedOperators = ALLOWED_DOMAIN_OPERATORS[_datatype].values().map(operator => {
        if (_domainConfig[operator]) {
            _domainConfig[operator].call(this);
        }
    });

    // expressionEval(appliedOperators)
}
